# ==================== 主程序：循环测试 ====================
def main():
    global logger
    # 手动输入三个路径（仅一次）
    dll_path = input("请输入 sendkey DLL 文件路径: ").strip()
    flash_s19 = input("请输入 flash_drive 包 S19 文件路径: ").strip()
    boot_s19 = input("请输入 boot_driver 包 S19 文件路径: ").strip()

    if not os.path.isfile(dll_path):
        print(f"DLL文件不存在: {dll_path}")
        return
    if not os.path.isfile(flash_s19):
        print(f"Flash S19文件不存在: {flash_s19}")
        return
    if not os.path.isfile(boot_s19):
        print(f"Boot S19文件不存在: {boot_s19}")
        return

    # 创建日志对象
    logger = TestLogger()

    # 循环次数
    LOOP_COUNT = 1
    success_count = 0
    fail_count = 0

    logger.log(f"开始循环烧录测试，共 {LOOP_COUNT} 次")
    start_time = time.time()

    for i in range(1, LOOP_COUNT + 1):
        result = perform_flash(dll_path, flash_s19, boot_s19, i)
        if result:
            success_count += 1
        else:
            fail_count += 1
        # 两次烧录之间等待一段时间，让ECU稳定
        time.sleep(2)

    elapsed = time.time() - start_time
    logger.log("\n" + "="*60)
    logger.log("循环测试结束")
    logger.log(f"总次数: {LOOP_COUNT}")
    logger.log(f"成功: {success_count}")
    logger.log(f"失败: {fail_count}")
    logger.log(f"成功率: {success_count/LOOP_COUNT*100:.2f}%")
    logger.log(f"总耗时: {elapsed:.2f} 秒, 平均每次: {elapsed/LOOP_COUNT:.2f} 秒")
    logger.log("="*60)

if __name__ == "__main__":
    main()